#include <stdio.h>
#include <stdlib.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int main() {
    int d, T;
    scanf("%d %d", &d, &T);
    while (T--) {
        int x1, y1, x2, y2;
        scanf("%d %d %d %d", &x1, &y1, &x2, &y2);
        int total = (x2 - x1 + 1) * (y2 - y1 + 1);
        int win = 0;
        for (int i = x1; i <= x2; i++) {
            for (int j = y1; j <= y2; j++) {
                int x = i, y = j;
                while (x > 0 && y > 0) {
                    if (x % d == 0 && y % d == 0) {
                        x -= d;
                        y -= d;
                    } else if (x > y) {
                        x--;
                    } else {
                        y--;
                    }
                }
                if ((x + y) % 2 == 1) win++;
            }
        }
        int g = gcd(win, total);
        printf("%d/%d\n", win / g, total / g);
    }
    return 0;
}

