        if (b == 0) return a;
        return gcd(b, a % b);
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int d = sc.nextInt();
        int T = sc.nextInt();
        while (T-- > 0) {
            int x1 = sc.nextInt();
            int y1 = sc.nextInt();
            int x2 = sc.nextInt();
            int y2 = sc.nextInt();
            int total = (x2 - x1 + 1) * (y2 - y1 + 1);
            int win = 0;
            for (int i = x1; i <= x2; i++) {
                for (int j = y1; j <= y2; j++) {
                    int x = i, y = j;
                    while (x > 0 && y > 0) {
                        if (x % d == 0 && y % d == 0) {
                            x -= d;
                            y -= d;
                        } else if (x > y) {
                            x--;
                        } else {
                            y--;
                        }
                    }
                    if ((x + y) % 2 == 1) win++;
                }
            }
            int g = gcd(win, total);
            System.out.println(win / g + "/" + total / g);
